+                }
+            }
+            group(Connection)
+            {
+                Caption = 'Connection Settings';
+                field("Endpoint URL"; Rec."Endpoint URL")
+                {
+                    ApplicationArea = All;
+                    ToolTip = 'Specifies the Azure Foundry endpoint URL.';
+                    ShowMandatory = true;
+                }
+                field("API Version"; Rec."API Version")
+                {
+                    ApplicationArea = All;
+                    ToolTip = 'Specifies the API version to use for Azure Foundry.';
+                }
+                field("Timeout (seconds)"; Rec."Timeout (seconds)")
+                {
+                    ApplicationArea = All;
+                    ToolTip = 'Specifies the timeout in seconds for API requests.';
+                }
+            }
+            group(Authentication)
+            {
+                Caption = 'Authentication';
+                field("Tenant ID"; Rec."Tenant ID")
+                {
+                    ApplicationArea = All;
+                    ToolTip = 'Specifies the Azure AD Tenant ID.';
+                    ShowMandatory = true;
+                }
+                field("Client ID"; Rec."Client ID")
+                {
+                    ApplicationArea = All;
+                    ToolTip = 'Specifies the Azure AD Client ID (Application ID).';
+                    ShowMandatory = true;
+                }
+                field("Client Secret"; Rec."Client Secret")
+                {
+                    ApplicationArea = All;
+                    ToolTip = 'Specifies the Azure AD Client Secret.';
+                    ShowMandatory = true;
+                    ExtendedDatatype = Masked;
+                }
+                field("Subscription Key"; Rec."Subscription Key")
+                {
+                    ApplicationArea = All;
+                    ToolTip = 'Specifies the Azure subscription key for API access.';
+                    ExtendedDatatype = Masked;
+                }
+                field("API Key"; Rec."API Key")
+                {
+                    ApplicationArea = All;
+                    ToolTip = 'Specifies the API key for Azure Foundry access.';
+                    ExtendedDatatype = Masked;
+                }
+            }
+            group(Workspace)
+            {
+                Caption = 'Workspace Information';
+                field("Resource Group"; Rec."Resource Group")
+                {
+                    ApplicationArea = All;
+                    ToolTip = 'Specifies the Azure Resource Group name.';
+                }
+                field("Workspace Name"; Rec."Workspace Name")
+                {
+                    ApplicationArea = All;
+                    ToolTip = 'Specifies the Azure Foundry workspace name.';
+                }
+            }
+            group(Status)
+            {
+                Caption = 'Connection Status';
+                field("Connection Status"; Rec."Connection Status")
+                {
+                    ApplicationArea = All;
+                    ToolTip = 'Shows the status of the last connection test.';
+                    Editable = false;
+                    StyleExpr = StatusStyle;
+                }
+                field("Last Connection Test"; Rec."Last Connection Test")
+                {
+                    ApplicationArea = All;
+                    ToolTip = 'Shows when the last connection test was performed.';
+                    Editable = false;
+                }
+            }
+        }
+    }
+
+    actions
+    {
+        area(Processing)
+        {
+            action(TestConnection)
+            {
+                ApplicationArea = All;
+                Caption = 'Test Connection';
+                ToolTip = 'Test the connection to Azure Foundry with the current settings.';
+                Image = ValidateEmailLoggingSetup;
+                Promoted = true;
+                PromotedCategory = Process;
+                PromotedIsBig = true;
+
+                trigger OnAction()
+                var
+                    AzureFoundryConnector: Codeunit "Azure Foundry Connector";
+                begin
+                    if AzureFoundryConnector.TestConnection() then
+                        Message('Connection test successful!')
+                    else
+                        Message('Connection test failed. Please check your settings.');
+
+                    CurrPage.Update(false);
+                end;
+            }
+            action(ClearCredentials)
+            {
+                ApplicationArea = All;
+                Caption = 'Clear Credentials';
+                ToolTip = 'Clear all stored credentials and API keys.';
+                Image = Delete;
+                Promoted = true;
+                PromotedCategory = Process;
+
+                trigger OnAction()
+                begin
+                    if Confirm('Are you sure you want to clear all credentials?') then begin
+                        Rec."Subscription Key" := '';
+                        Rec."API Key" := '';
+                        Rec."Client Secret" := '';
+                        Rec.Modify(true);
+                        Message('Credentials cleared successfully.');
+                    end;
+                end;
+            }
+        }
+    }
+
+    trigger OnOpenPage()
+    begin
+        Rec.Get();
+        UpdateStatusStyle();
+    end;
+
+    trigger OnAfterGetRecord()
+    begin
+        UpdateStatusStyle();
+    end;
+
+    local procedure UpdateStatusStyle()
+    begin
+        case Rec."Connection Status" of
+            Rec."Connection Status"::Success:
+                StatusStyle := 'Favorable';
+            Rec."Connection Status"::Failed:
+                StatusStyle := 'Unfavorable';
+            else
+                StatusStyle := 'Standard';
+        end;
+    end;
+
+    var
+        StatusStyle: Text;
+}
